{
  "error": {
    "code": "Unauthorized",
    "message": "AKV10000: Request is missing a Bearer or PoP token.",
    "innererror": {
      "code": "MissingAccessToken"
    }
  }
}

// Cause: sent an ARM token (aud=management.azure.com) to a Key Vault endpoint
// Fix: re-acquire the token with --resource https://vault.azure.net

import { DefaultAzureCredential } from "@azure/identity";
import { StorageManagementClient } from "@azure/arm-storage";      // control plane
import { BlobServiceClient } from "@azure/storage-blob";           // data plane

const credential = new DefaultAzureCredential();
const subscriptionId = "00000000-0000-0000-0000-000000000000";

// Control plane: list all storage accounts
const mgmtClient = new StorageManagementClient(credential, subscriptionId);

const accounts = [];
for await (const acct of mgmtClient.storageAccounts.list()) {
    accounts.push(acct.name);
}
console.log("Accounts:", accounts);

// Data plane: list blobs in a container
const blobClient = new BlobServiceClient(
    "https://mystorageaccount.blob.core.windows.net",
    credential   // SDK automatically requests storage.azure.com audience
);

const containerClient = blobClient.getContainerClient("uploads");
for await (const blob of containerClient.listBlobsFlat()) {
    console.log(`  ${blob.name} — ${blob.properties.contentLength} bytes`);
}

